index 2239418..c945d4e 100644
--- a/retry.py
+++ b/retry.py
@@ -18,13 +18,13 @@ def retry(attempts: int = 3, exceptions: tuple = (Exception,), on_retry=None):
         @functools.wraps(func)
         def wrapper(*args, **kwargs):
             last_exc = None
-            for attempt in range(1, attempts):
+            for attempt in range(1, attempts + 1):  # Change: Add 1 to include the last attempt
                 try:
                     return func(*args, **kwargs)
                 except exceptions as exc:
                     last_exc = exc
                     if on_retry is not None:
